SELECT SUM(quantity) AS total_dump_quantity
FROM sewage_dumps
WHERE site_id = 1;

SELECT waterway_name
FROM waterways
WHERE pollution_level = 'high';

SELECT site_id
FROM sewage_dumps
WHERE pollutant_concentration > 100;

SELECT waterway_name
FROM waterways
WHERE pollution_level = (SELECT MAX(pollution_level) FROM waterways);

SELECT SUM(quantity) AS total_dumped
FROM sewage_dumps
WHERE site_id = 0;
